---
import { cn } from "@/lib/utils";
import type { HTMLAttributes } from "astro/types";

interface Props extends HTMLAttributes<"button"> {
  class?: string;
}

const { class: className = "", ...rest } = Astro.props as Props;
---

<button
  {...rest}
  data-slot="dialog-close"
  data-dialog-close
  class={cn("absolute top-2 right-2 inline-flex items-center gap-2", className)}
>
  <slot />
  {!Astro.slots.has("default") && <span class="sr-only">Close</span>}
</button>

---
import { cn } from "@/lib/utils";
import type { HTMLAttributes } from "astro/types";

import DialogClose from "./DialogClose.astro";
import DialogOverlay from "./DialogOverlay.astro";
import SemanticIcon from "../icon/SemanticIcon.astro";

interface Props extends HTMLAttributes<"div"> {
  showCloseButton?: boolean;
}

const {
  showCloseButton = true,
  class: className = "",
  ...rest
} = Astro.props as Props;
---

<div data-slot="dialog-portal" class="z-50 isolate absolute">
  <DialogOverlay />
  <div
    data-slot="dialog-content"
    hidden
    class={cn(
      "bg-background data-open:animate-in data-closed:animate-out data-closed:fade-out-0 data-open:fade-in-0 data-closed:zoom-out-95 data-open:zoom-in-95 ring-foreground/10 grid max-w-[calc(100%-2rem)] gap-4 rounded-xl p-4 text-sm ring-1 duration-100 sm:max-w-sm fixed top-1/2 left-1/2 z-50 w-full -translate-x-1/2 -translate-y-1/2 outline-none",
      className,
    )}
    {...rest}
  >
    <slot />
    {
      showCloseButton && (
        <DialogClose>
          <SemanticIcon name="x" />
          <span class="sr-only">Close</span>
        </DialogClose>
      )
    }
  </div>
</div>

